solution_code:
#include <stdio.h>
void swap(int *a, int *b) {
    int tmp = *a;
    *a = *b;
    *b = tmp;
}
int main(void) {
    int x = 10, y = 20;
    printf("Avant : x=%d y=%d\n", x, y);
    swap(&x, &y);
    printf("Apres swap : x=%d y=%d\n", x, y);
    int val = 99;
    int *p = &val;
    int **pp = &p;
    printf("Via **pp : %d\n", **pp);
    return 0;
}

