#include <stdio.h>

// ★ Stage 0 — Exemple complet
void swap(int *a, int *b) {
    int tmp = *a;  // ★ déréférencement
    *a = *b;
    *b = tmp;
}
int main(void) {
    int x = 10, y = 20;
    printf("Avant : x=%d y=%d\n", x, y);
    swap(&x, &y);  // ★ passage par adresse
    printf("Apres swap : x=%d y=%d\n", x, y);
    int val = 99;
    int *p = &val;
    int **pp = &p;  // ★ pointeur vers pointeur
    printf("Via **pp : %d\n", **pp); // ★ double déréférencement
    return 0;
}

